291→    const handleSubmit = async(e) =>{
292→        e.stopPropagation();
293→        e.preventDefault();
294→        try {
295→            setUploadingUserData(true)
296→            const formdata = new FormData();
297→            if(imageFile){
298→                formdata.append('image', imageFile);
299→            }
300→            if(bio && name){
301→                formdata.append('name', name)
302→                formdata.append('bio', bio)
303→                if(setupUsername && setupUsername.length >= 3){
304→                    formdata.append('username', setupUsername)
305→                }
306→            }
307→            const {data} = await submitProfileData(formdata, session?.access_token);
308→            // if(data){
309→            //     console.log(data)
310→            // }
311→            setShowWelcomeMessage(true)
312→        } catch (error) {
313→            throw new Error('error uploading data')
314→        } finally {
